// styles/global.js
import css from "styled-jsx/css";

export default css.global`
  body {
    margin: 0;
    padding: 0;
    background-color: #101010;
  }

  a {
    text-decoration: none;
  }
  h2 {
    font-family: 'Roboto Mono', monospace;
  }
`;
